import { useEffect, useState } from "react";
import { getUsers, deleteUser } from "../api/api";
import UserForm from "../components/UserForm";
import "./Home.css";

export default function Home({ setIsLoggedIn }) {
  const [users, setUsers] = useState([]);

  useEffect(() => {
    loadUsers();
  }, []);

  useEffect(() => {
  const token = localStorage.getItem("token");

  if (!token) {
    setIsLoggedIn(false);
  }
}, []);

  const loadUsers = async () => {
    const data = await getUsers();

    if (data.detail === "Invalid token") {
    localStorage.removeItem("token");
    setIsLoggedIn(false);
  } else {
    setUsers(data);
  }
  };

  const handleDelete = async (id) => {
    await deleteUser(id);
    loadUsers();
  };

  const handleLogout = () => {
  localStorage.removeItem("token");   
  window.location.reload();  
  setIsLoggedIn(false);  
   navigate("/");      
  };

  const [editingUser, setEditingUser] = useState(null);

  return (
    
    <div className="container">
      <h2 className="title">USER PAGE</h2>

      <button onClick={handleLogout} className="logout_btn" >Logout</button>

      <UserForm reload={loadUsers}
                editingUser={editingUser}
                setEditingUser={setEditingUser} />
       <br/><h3 style={{fontFamily: "serif", fontWeight: "bold"}}>Existing users :</h3>

      <div style={{ marginTop: "20px" }}>
        {users.map((user, index) => (
          <div
            className="user-row"
            key={user.id}
            style={{
              display: "flex",
              justifyContent: "space-between",
              marginBottom: "10px",
              padding: "10px",
              border: "1px solid #eee",
              borderRadius: "5px",
              alignContent: "center",
            }}
          >
            <span>
              {index + 1}. {user.name}  {user.email}
            </span>

            <div style={{display: "flex", gap: "15px "}}>
            <button className="delete"
              onClick={() => handleDelete(user.id)}
            >Delete</button>
            <button className="edit" onClick={() => setEditingUser(user)}>Edit</button>
            
          </div>
          </div>
        ))}
      </div>
      
    </div>
  );
}
